<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8"/>
<meta name="viewport" content="width=device-width, initial-scale=1.0"/>
<title>SJVN Limited — Energy Projects India</title>
<link rel="preconnect" href="https://fonts.googleapis.com"/>
<link href="https://fonts.googleapis.com/css2?family=Rajdhani:wght@400;500;600;700&family=DM+Sans:wght@300;400;500&display=swap" rel="stylesheet"/>
<style>
:root {
  --navy:    #080f1e;
  --navy2:   #0c1a32;
  --navy3:   #122040;
  --blue:    #1251aa;
  --cyan:    #00b4d8;
  --gold:    #f4a100;
  --green:   #00c9a7;
  --wind:    #a78bfa;
  --solar:   #fbbf24;
  --hydro:   #22d3ee;
  --land:    #1a3a2a;
  --land-h:  #22503a;
  --border:  rgba(255,255,255,0.07);
  --text:    #e2e8f0;
  --muted:   #7890a8;
  --card:    rgba(8,18,38,0.97);
  --fh: 'Rajdhani', sans-serif;
  --fb: 'DM Sans', sans-serif;
}
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
html,body{height:100%;overflow:hidden}
body{background:var(--navy);color:var(--text);font-family:var(--fb);display:flex;flex-direction:column}

/* grid lines bg */
body::before{content:'';position:fixed;inset:0;pointer-events:none;z-index:0;
  background-image:linear-gradient(rgba(18,81,170,0.05) 1px,transparent 1px),linear-gradient(90deg,rgba(18,81,170,0.05) 1px,transparent 1px);
  background-size:44px 44px;}

/* ── HEADER ── */
header{position:relative;z-index:10;display:flex;align-items:center;justify-content:space-between;
  padding:12px 28px;border-bottom:1px solid var(--border);background:rgba(8,15,30,0.92);
  backdrop-filter:blur(16px);flex-shrink:0;gap:12px;flex-wrap:wrap;}
.logo{display:flex;align-items:center;gap:12px}
.logo-badge{width:42px;height:42px;border-radius:10px;flex-shrink:0;display:flex;align-items:center;justify-content:center;
  background:linear-gradient(135deg,#1251aa 0%,#00b4d8 100%);
  font-family:var(--fh);font-weight:700;font-size:14px;color:#fff;letter-spacing:1px;text-align:center;line-height:1.1}
.logo h1{font-family:var(--fh);font-size:20px;font-weight:700;color:#fff;letter-spacing:1.5px}
.logo p{font-size:10px;color:var(--muted);letter-spacing:2px;text-transform:uppercase;margin-top:1px}
.hstats{display:flex;gap:20px;flex-wrap:wrap}
.hs{text-align:center}
.hs-n{font-family:var(--fh);font-size:20px;font-weight:700;line-height:1}
.hs-n.c-hydro{color:var(--hydro)} .hs-n.c-solar{color:var(--solar)} .hs-n.c-wind{color:var(--wind)} .hs-n.c-total{color:var(--cyan)}
.hs-l{font-size:9px;color:var(--muted);text-transform:uppercase;letter-spacing:1.5px;margin-top:2px}

/* ── LAYOUT ── */
.layout{display:flex;flex:1;overflow:hidden;position:relative;z-index:1}

/* ── MAP ── */
.map-wrap{flex:1;position:relative;overflow:hidden;background:#040c18}
#india-svg{width:100%;height:100%;display:block}
.state-path{fill:var(--land);stroke:#0d2a1a;stroke-width:.4;transition:fill .18s,filter .18s;cursor:default}
.state-path:hover{fill:var(--land-h);filter:brightness(1.08)}
.state-path.hl{fill:#1a4a30;filter:brightness(1.15)}

/* ── MARKERS ── */
.mk{cursor:pointer}
.mk circle.pulse{animation:pulse 2.8s ease-in-out infinite;transform-box:fill-box;transform-origin:center}
@keyframes pulse{0%,100%{opacity:.6;transform:scale(1)}50%{opacity:.08;transform:scale(2.5)}}
.mk:hover circle.outer{r:13 !important}
.mk.sel circle.inner{filter:brightness(1.5)}

/* ── TOOLTIP ── */
#tip{position:absolute;pointer-events:none;display:none;z-index:200;min-width:230px;max-width:270px}
.tip-card{background:rgba(5,14,30,0.97);border:1px solid rgba(0,180,216,0.4);border-radius:12px;
  padding:14px 16px;backdrop-filter:blur(20px);box-shadow:0 8px 32px rgba(0,0,0,0.6)}
.tip-name{font-family:var(--fh);font-size:15px;font-weight:700;color:#fff;line-height:1.2;margin-bottom:2px}
.tip-cap{font-family:var(--fh);font-size:26px;font-weight:700;line-height:1;margin-bottom:8px}
.tip-row{display:flex;gap:6px;font-size:11px;color:var(--muted);margin-bottom:3px;align-items:flex-start}
.tip-icon{font-size:11px;flex-shrink:0;margin-top:1px}
.tip-note{font-size:11px;color:rgba(120,144,168,0.9);margin-top:6px;padding-top:6px;border-top:1px solid var(--border);line-height:1.5}
.tip-tag{display:inline-flex;align-items:center;gap:5px;font-size:10px;font-weight:600;text-transform:uppercase;
  letter-spacing:1px;padding:3px 10px;border-radius:20px;margin-top:8px;margin-right:4px}
.tag-op{background:rgba(0,201,167,0.15);color:#00c9a7;border:1px solid rgba(0,201,167,0.35)}
.tag-uc{background:rgba(244,161,0,0.15);color:#fbbf24;border:1px solid rgba(244,161,0,0.35)}
.tag-pl{background:rgba(18,81,170,0.2);color:#7dd3fc;border:1px solid rgba(18,81,170,0.4)}
.type-hydro{background:rgba(34,211,238,0.12);color:#22d3ee;border:1px solid rgba(34,211,238,0.3)}
.type-solar{background:rgba(251,191,36,0.12);color:#fbbf24;border:1px solid rgba(251,191,36,0.3)}
.type-wind{background:rgba(167,139,250,0.12);color:#a78bfa;border:1px solid rgba(167,139,250,0.3)}

/* ── PANEL ── */
#panel{position:absolute;bottom:0;left:0;right:340px;z-index:100;
  background:linear-gradient(0deg,rgba(5,12,28,0.99) 0%,rgba(8,18,38,0.92) 100%);
  border-top:1px solid rgba(0,180,216,0.25);backdrop-filter:blur(14px);
  padding:16px 24px;display:grid;grid-template-columns:1fr 1fr 1fr 1fr auto;gap:14px;align-items:start;
  transform:translateY(100%);transition:transform .32s cubic-bezier(.4,0,.2,1)}
#panel.open{transform:translateY(0)}
.dp h4{font-size:9px;text-transform:uppercase;letter-spacing:2px;color:var(--muted);margin-bottom:4px;font-family:var(--fh)}
.dp p{font-family:var(--fh);font-size:14px;color:var(--text);font-weight:500;line-height:1.4}
.dp .big{font-size:24px!important;font-weight:700!important}
.panel-close{width:34px;height:34px;border-radius:8px;border:1px solid var(--border);background:rgba(255,255,255,0.05);
  color:var(--muted);cursor:pointer;font-size:16px;display:flex;align-items:center;justify-content:center;
  transition:all .18s;flex-shrink:0}
.panel-close:hover{background:rgba(255,255,255,0.1);color:var(--text)}

/* ── SIDEBAR ── */
.sidebar{width:340px;flex-shrink:0;background:rgba(6,14,28,0.98);border-left:1px solid var(--border);
  display:flex;flex-direction:column;overflow:hidden}
.sb-head{padding:16px 16px 10px;border-bottom:1px solid var(--border);flex-shrink:0}
.sb-head h2{font-family:var(--fh);font-size:13px;font-weight:700;color:#fff;letter-spacing:2px;text-transform:uppercase}
.sb-head p{font-size:11px;color:var(--muted);margin-top:2px}
.filters{display:flex;gap:4px;padding:8px 12px;border-bottom:1px solid var(--border);flex-shrink:0;flex-wrap:wrap}
.fb{flex:1;min-width:60px;padding:5px 4px;border-radius:6px;border:1px solid transparent;
  background:rgba(255,255,255,0.04);color:var(--muted);font-family:var(--fh);font-size:10px;font-weight:700;
  letter-spacing:.8px;cursor:pointer;transition:all .18s;text-transform:uppercase}
.fb.on{background:rgba(18,81,170,0.22);color:var(--cyan);border-color:rgba(0,180,216,0.35)}
.fb:hover:not(.on){background:rgba(255,255,255,0.07);color:var(--text)}
.plist{overflow-y:auto;flex:1;padding:6px 8px 12px;scrollbar-width:thin;scrollbar-color:var(--navy3) transparent}
.plist::-webkit-scrollbar{width:3px}
.plist::-webkit-scrollbar-thumb{background:var(--navy3);border-radius:4px}
.pi{display:flex;align-items:center;gap:9px;padding:9px 11px;border-radius:8px;cursor:pointer;
  transition:background .14s;margin-bottom:3px;border:1px solid transparent}
.pi:hover{background:rgba(255,255,255,0.04)}
.pi.sel{background:rgba(18,81,170,0.18);border-color:rgba(0,180,216,0.22)}
.pi-dot{width:9px;height:9px;border-radius:50%;flex-shrink:0}
.pi-info{flex:1;min-width:0}
.pi-name{font-family:var(--fh);font-size:12px;font-weight:600;color:#fff;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}
.pi-sub{font-size:10px;color:var(--muted);margin-top:1px}
.pi-cap{font-family:var(--fh);font-size:12px;font-weight:700;flex-shrink:0}
.legend{padding:10px 14px;border-top:1px solid var(--border);flex-shrink:0;display:grid;grid-template-columns:1fr 1fr;gap:5px 12px}
.lg-row{display:flex;align-items:center;gap:7px;font-size:10px;color:var(--muted)}
.lg-dot{width:9px;height:9px;border-radius:50%;flex-shrink:0}
.lg-sq{width:9px;height:9px;flex-shrink:0}

/* State label overlays */
.state-lbl{font-family:'Rajdhani',sans-serif;font-size:8px;fill:rgba(255,255,255,0.28);
  text-anchor:middle;pointer-events:none;font-weight:500;letter-spacing:0.5px}
.state-lbl.hl{fill:rgba(255,255,255,0.65)}

@media(max-width:900px){
  .layout{flex-direction:column}
  .sidebar{width:100%;max-height:280px;border-left:none;border-top:1px solid var(--border)}
  #panel{right:0;grid-template-columns:1fr 1fr}
}
</style>
</head>
<body>
<header>
  <div class="logo">
    <div class="logo-badge">SJ<br>VN</div>
    <div>
      <h1>SJVN LIMITED</h1>
      <p>Energy Projects — India</p>
    </div>
  </div>
  <div class="hstats">
    <div class="hs"><div class="hs-n c-total">2,630 MW</div><div class="hs-l">Total Operational</div></div>
    <div class="hs"><div class="hs-n c-hydro">1,972 MW</div><div class="hs-l">Hydro</div></div>
    <div class="hs"><div class="hs-n c-solar">558 MW</div><div class="hs-l">Solar</div></div>
    <div class="hs"><div class="hs-n c-wind">100 MW</div><div class="hs-l">Wind</div></div>
    <div class="hs"><div class="hs-n" style="color:#f97316">25</div><div class="hs-l">Total Projects</div></div>
  </div>
</header>

<div class="layout">
<div class="map-wrap" id="map-wrap">

