    <circle class="inner" cx="220" cy="400" r="3" fill="#fbbf24"/>
  </g>

  <!-- ═══ WIND — OPERATIONAL ═══ -->
  <!-- Khirasara Wind: Gujarat (near solar) -->
  <g class="mk" data-id="19" onclick="sel(19)" onmouseover="tip(event,19)" onmouseout="untip()">
    <circle class="pulse" cx="170" cy="490" r="16" fill="#a78bfa" opacity=".55"/>
    <circle class="outer" cx="170" cy="490" r="8.5" fill="#a78bfa" stroke="#fff" stroke-width="1.5" style="transition:r .2s"/>
    <circle class="inner" cx="170" cy="490" r="3" fill="#fff"/>
  </g>

  <!-- ═══ WIND — UNDER CONSTRUCTION ═══ -->
  <!-- SJVN Wind Rajasthan -->
  <g class="mk" data-id="20" onclick="sel(20)" onmouseover="tip(event,20)" onmouseout="untip()">
    <circle class="pulse" cx="248" cy="370" r="15" fill="#c084fc" opacity=".55"/>
    <circle class="outer" cx="248" cy="370" r="8" fill="#c084fc" stroke="#fff" stroke-width="1.5" style="transition:r .2s"/>
    <circle class="inner" cx="248" cy="370" r="3" fill="#fff"/>
  </g>
  <!-- SJVN Wind Gujarat -->
  <g class="mk" data-id="21" onclick="sel(21)" onmouseover="tip(event,21)" onmouseout="untip()">
    <circle class="pulse" cx="195" cy="488" r="14" fill="#c084fc" opacity=".55"/>
    <circle class="outer" cx="195" cy="488" r="7.5" fill="#c084fc" stroke="#fff" stroke-width="1.5" style="transition:r .2s"/>
    <circle class="inner" cx="195" cy="488" r="2.8" fill="#fff"/>
  </g>

  <!-- ═══ WIND — PLANNED ═══ -->
  <!-- SJVN Wind HP Himachal -->
  <g class="mk" data-id="22" onclick="sel(22)" onmouseover="tip(event,22)" onmouseout="untip()">
    <circle class="pulse" cx="348" cy="205" r="14" fill="#6d8cdb" opacity=".55"/>
    <circle class="outer" cx="348" cy="205" r="7.5" fill="#6d8cdb" stroke="#a78bfa" stroke-width="1.5" style="transition:r .2s"/>
    <circle class="inner" cx="348" cy="205" r="2.8" fill="#a78bfa"/>
  </g>
  <!-- SJVN Wind Andhra Pradesh -->
  <g class="mk" data-id="23" onclick="sel(23)" onmouseover="tip(event,23)" onmouseout="untip()">
    <circle class="pulse" cx="440" cy="705" r="14" fill="#6d8cdb" opacity=".55"/>
    <circle class="outer" cx="440" cy="705" r="7.5" fill="#6d8cdb" stroke="#a78bfa" stroke-width="1.5" style="transition:r .2s"/>
    <circle class="inner" cx="440" cy="705" r="2.8" fill="#a78bfa"/>
  </g>
  <!-- SJVN Solar Uttarakhand planned -->
  <g class="mk" data-id="24" onclick="sel(24)" onmouseover="tip(event,24)" onmouseout="untip()">
    <circle class="pulse" cx="418" cy="268" r="14" fill="#6d8cdb" opacity=".55"/>
    <circle class="outer" cx="418" cy="268" r="7.5" fill="#6d8cdb" stroke="#fbbf24" stroke-width="1.5" style="transition:r .2s"/>
    <circle class="inner" cx="418" cy="268" r="2.8" fill="#fbbf24"/>
  </g>

  <!-- Compass rose -->
  <g transform="translate(52,940)" opacity="0.5">
    <line x1="0" y1="-18" x2="0" y2="18" stroke="rgba(255,255,255,.3)" stroke-width=".8"/>
    <line x1="-18" y1="0" x2="18" y2="0" stroke="rgba(255,255,255,.3)" stroke-width=".8"/>
    <polygon points="0,-18 -4,-7 0,-12 4,-7" fill="#00b4d8"/>
    <text x="0" y="-22" text-anchor="middle" font-size="10" fill="#00b4d8" font-family="Rajdhani">N</text>
  </g>
  <!-- Scale bar -->
  <g transform="translate(88,944)" opacity="0.42">
    <rect x="0" y="-2" width="100" height="4" fill="none" stroke="rgba(255,255,255,.35)" stroke-width=".8"/>
    <rect x="0" y="-2" width="50" height="4" fill="rgba(255,255,255,.12)"/>
    <text x="50" y="-7" text-anchor="middle" font-size="9" fill="rgba(255,255,255,.4)" font-family="Rajdhani">500 km</text>
  </g>

  <!-- Bay of Bengal / Arabian Sea labels -->
  <text x="700" y="600" font-family="Rajdhani" font-size="13" fill="rgba(0,180,216,.22)" text-anchor="middle" transform="rotate(-20,700,600)">Bay of Bengal</text>
  <text x="120" y="650" font-family="Rajdhani" font-size="13" fill="rgba(0,180,216,.22)" text-anchor="middle" transform="rotate(20,120,650)">Arabian Sea</text>
  <text x="400" y="960" font-family="Rajdhani" font-size="14" fill="rgba(0,180,216,.18)" text-anchor="middle">Indian Ocean</text>

</svg>

<!-- TOOLTIP -->
<div id="tip">
  <div class="tip-card">
    <div class="tip-name" id="tn"></div>
    <div class="tip-cap" id="tc"></div>
    <div class="tip-row"><span class="tip-icon">📍</span><span id="tl"></span></div>
    <div class="tip-row"><span class="tip-icon">⚡</span><span id="te"></span></div>
    <div class="tip-note" id="tnote"></div>
    <div style="margin-top:8px">
      <span class="tip-tag" id="tt-status"></span>
      <span class="tip-tag" id="tt-type"></span>
    </div>
  </div>
</div>

<!-- DETAIL PANEL -->
<div id="panel">
  <div class="dp"><h4>Project</h4><p id="dp-n">—</p></div>
  <div class="dp"><h4>Capacity</h4><p class="big" id="dp-c">—</p></div>
  <div class="dp"><h4>Type / Status</h4><p id="dp-t">—</p></div>
  <div class="dp"><h4>Location</h4><p id="dp-l">—</p></div>
  <button class="panel-close" onclick="closePanel()">✕</button>
</div>
</div><!-- /map-wrap -->

<!-- SIDEBAR -->
<div class="sidebar">
  <div class="sb-head">
    <h2>SJVN Projects</h2>
    <p>Click a marker or list item for details</p>
  </div>
  <div class="filters">
    <button class="fb on" onclick="fil('all',this)">All</button>
    <button class="fb" onclick="fil('Hydro',this)">💧 Hydro</button>
    <button class="fb" onclick="fil('Solar',this)">☀️ Solar</button>
    <button class="fb" onclick="fil('Wind',this)">💨 Wind</button>
    <button class="fb" onclick="fil('Operational',this)">Active</button>
    <button class="fb" onclick="fil('Under Construction',this)">Build</button>
    <button class="fb" onclick="fil('Planned',this)">Plan</button>
  </div>
  <div class="plist" id="plist"></div>
  <div class="legend">
    <div class="lg-row"><div class="lg-dot" style="background:#22d3ee"></div><span>Hydro</span></div>
    <div class="lg-row"><div class="lg-dot" style="background:#fbbf24"></div><span>Solar</span></div>
    <div class="lg-row"><div class="lg-dot" style="background:#a78bfa"></div><span>Wind</span></div>
    <div class="lg-row" style="grid-column:1/-1;margin-top:4px;font-size:9px;color:#556;letter-spacing:1px;text-transform:uppercase">Status indicator:</div>
    <div class="lg-row"><div class="lg-dot" style="background:#00c9a7"></div><span>Operational</span></div>
    <div class="lg-row"><div class="lg-dot" style="background:#f97316"></div><span>Under Construction</span></div>
    <div class="lg-row"><div class="lg-dot" style="background:#6d8cdb"></div><span>Planned</span></div>
  </div>
</div>
</div><!-- /layout -->

<script>
const P = [
  {id:0, name:"Nathpa Jhakri HPS",    cap:"1,500 MW", mw:1500, loc:"Shimla dist, Himachal Pradesh",    type:"Hydro",  status:"Operational",       color:"#22d3ee", note:"India's largest underground hydropower station. 6×250 MW Francis turbines on River Sutlej. Commissioned 2004."},
  {id:1, name:"Rampur HPS",           cap:"412 MW",   mw:412,  loc:"Kullu dist, Himachal Pradesh",     type:"Hydro",  status:"Operational",       color:"#22d3ee", note:"6×68.67 MW run-of-river downstream of NJHPS on River Sutlej. Commissioned 2014."},
  {id:2, name:"Naitwar Mori HPS",     cap:"60 MW",    mw:60,   loc:"Uttarkashi, Uttarakhand",          type:"Hydro",  status:"Operational",       color:"#22d3ee", note:"2×30 MW run-of-river project on River Tons. Commissioned December 2023."},
  {id:3, name:"Luhri Stage-I HEP",    cap:"210 MW",   mw:210,  loc:"Mandi dist, Himachal Pradesh",     type:"Hydro",  status:"Under Construction", color:"#f4a100", note:"4×52.5 MW run-of-river on River Sutlej. Construction ongoing."},
  {id:4, name:"Dhaulasidh HEP",       cap:"66 MW",    mw:66,   loc:"Kangra dist, Himachal Pradesh",    type:"Hydro",  status:"Under Construction", color:"#f4a100", note:"3×22 MW run-of-river on River Beas. Under construction."},
  {id:5, name:"Sunni Dam HEP",        cap:"382 MW",   mw:382,  loc:"Shimla dist, Himachal Pradesh",    type:"Hydro",  status:"Under Construction", color:"#f4a100", note:"382 MW storage-type dam on River Sutlej. Under construction."},
  {id:6, name:"Etalin HEP",           cap:"3,097 MW", mw:3097, loc:"Dibang Valley, Arunachal Pradesh", type:"Hydro",  status:"Planned",            color:"#6d8cdb", note:"Largest in portfolio. 12×258 MW on Dibang & Tangon rivers. MoA signed with AP Govt."},
  {id:7, name:"Attunli HEP",          cap:"680 MW",   mw:680,  loc:"Dibang Valley, Arunachal Pradesh", type:"Hydro",  status:"Planned",            color:"#6d8cdb", note:"4×170 MW project. MoA signed with Arunachal Pradesh Government."},
  {id:8, name:"Emini HEP",            cap:"500 MW",   mw:500,  loc:"Dibang Valley, Arunachal Pradesh", type:"Hydro",  status:"Planned",            color:"#6d8cdb", note:"500 MW run-of-river. MoA signed with Arunachal Pradesh Government."},
  {id:9, name:"Amulin HEP",           cap:"420 MW",   mw:420,  loc:"Dibang Valley, Arunachal Pradesh", type:"Hydro",  status:"Planned",            color:"#6d8cdb", note:"420 MW hydro project allotted to SJVN in Arunachal Pradesh."},
  {id:10,name:"Mihumdon HEP",         cap:"400 MW",   mw:400,  loc:"Dibang Valley, Arunachal Pradesh", type:"Hydro",  status:"Planned",            color:"#6d8cdb", note:"400 MW hydro project allotted to SJVN by Arunachal Pradesh Govt."},
  {id:11,name:"Sadla Solar PV",        cap:"90 MW",    mw:90,   loc:"Surendranagar, Gujarat",           type:"Solar",  status:"Operational",       color:"#fbbf24", note:"90 MW ground-mounted solar park. Commissioned 2022. Part of SJVN's renewable expansion."},
  {id:12,name:"Raghanesda Solar PV",   cap:"75 MW",    mw:75,   loc:"Patan dist, Gujarat",              type:"Solar",  status:"Operational",       color:"#fbbf24", note:"75 MW solar project operational in Gujarat. Long-term PPA signed with GUVNL."},
  {id:13,name:"Khirasara Solar PV",    cap:"50 MW",    mw:50,   loc:"Rajkot dist, Gujarat",             type:"Solar",  status:"Operational",       color:"#fbbf24", note:"50 MW solar project co-located with wind in Khirasara, Gujarat."},
  {id:14,name:"Bikaner Solar",         cap:"1,000 MW", mw:1000, loc:"Bikaner, Rajasthan",               type:"Solar",  status:"Under Construction", color:"#f97316", note:"1,000 MW ultra-mega solar park under development in Bikaner, Rajasthan. Major renewable push."},
  {id:15,name:"Fatehgarh Solar",       cap:"300 MW",   mw:300,  loc:"Jaisalmer, Rajasthan",             type:"Solar",  status:"Under Construction", color:"#f97316", note:"300 MW solar project in Fatehgarh Solar Zone, Jaisalmer. Under construction."},
  {id:16,name:"Dholera Solar",         cap:"200 MW",   mw:200,  loc:"Dholera SIR, Gujarat",             type:"Solar",  status:"Under Construction", color:"#f97316", note:"200 MW solar in Dholera Special Investment Region under development."},
  {id:17,name:"MP Solar Project",      cap:"500 MW",   mw:500,  loc:"Madhya Pradesh",                   type:"Solar",  status:"Planned",            color:"#6d8cdb", note:"500 MW solar project planned in Madhya Pradesh under SJVN's renewable expansion pipeline."},
  {id:18,name:"Rajasthan Solar Park",  cap:"750 MW",   mw:750,  loc:"Barmer/Jaisalmer, Rajasthan",      type:"Solar",  status:"Planned",            color:"#6d8cdb", note:"750 MW planned solar capacity in Rajasthan as part of SJVN's 5,000 MW renewable target."},
  {id:19,name:"Khirasara Wind Farm",   cap:"50 MW",    mw:50,   loc:"Rajkot dist, Gujarat",             type:"Wind",   status:"Operational",       color:"#a78bfa", note:"50 MW wind farm operational at Khirasara. Co-located with solar PV plant."},
  {id:20,name:"Rajasthan Wind Project",cap:"200 MW",   mw:200,  loc:"Jaisalmer, Rajasthan",             type:"Wind",   status:"Under Construction", color:"#c084fc", note:"200 MW wind energy project under construction in high wind-potential Jaisalmer belt."},
  {id:21,name:"Gujarat Wind Project",  cap:"100 MW",   mw:100,  loc:"Kutch dist, Gujarat",              type:"Wind",   status:"Under Construction", color:"#c084fc", note:"100 MW wind project in Kutch, Gujarat. Construction ongoing."},
  {id:22,name:"HP Wind Project",       cap:"100 MW",   mw:100,  loc:"Lahaul-Spiti, Himachal Pradesh",   type:"Wind",   status:"Planned",            color:"#6d8cdb", note:"Planned 100 MW wind project in high-altitude Lahaul-Spiti district, Himachal Pradesh."},
  {id:23,name:"Andhra Wind Project",   cap:"150 MW",   mw:150,  loc:"Kurnool, Andhra Pradesh",          type:"Wind",   status:"Planned",            color:"#6d8cdb", note:"150 MW wind project planned in Kurnool district, Andhra Pradesh."},
  {id:24,name:"Uttarakhand Solar",     cap:"50 MW",    mw:50,   loc:"Dehradun, Uttarakhand",            type:"Solar",  status:"Planned",            color:"#6d8cdb", note:"50 MW solar project planned in Uttarakhand to complement the existing hydro portfolio."},
];

const typeColor={Hydro:"#22d3ee",Solar:"#fbbf24",Wind:"#a78bfa"};
const statusCls={Operational:"tag-op","Under Construction":"tag-uc",Planned:"tag-pl"};
const typeCls={Hydro:"type-hydro",Solar:"type-solar",Wind:"type-wind"};

let activeId=null, curFilter="all";

function buildList(){
  const el=document.getElementById("plist"); el.innerHTML="";
  P.forEach(p=>{
    const show=curFilter==="all"||p.type===curFilter||p.status===curFilter||
      (curFilter==="Under Construction"&&p.status==="Under Construction");
    if(!show)return;
    const d=document.createElement("div"); d.className="pi"+(activeId===p.id?" sel":""); d.dataset.id=p.id;
    const cap=`<span style="color:${typeColor[p.type]}">${p.cap}</span>`;
    d.innerHTML=`<div class="pi-dot" style="background:${p.color}"></div>
      <div class="pi-info"><div class="pi-name">${p.name}</div>
      <div class="pi-sub">${p.type} · ${p.loc.split(",").slice(-1)[0].trim()}</div></div>
      <div class="pi-cap">${cap}</div>`;
    d.onclick=()=>sel(p.id); el.appendChild(d);
  });
}

function fil(f,btn){
  curFilter=f;
  document.querySelectorAll(".fb").forEach(b=>b.classList.remove("on"));
  btn.classList.add("on"); buildList();
}

function sel(id){
  activeId=(activeId===id)?null:id;
  document.querySelectorAll(".pi").forEach(e=>e.classList.toggle("sel",+e.dataset.id===activeId));
  document.querySelectorAll(".mk").forEach(e=>e.classList.toggle("sel",+e.dataset.id===activeId));
  const panel=document.getElementById("panel");
  if(activeId!==null){
    const p=P[activeId];
    document.getElementById("dp-n").textContent=p.name;
    document.getElementById("dp-c").textContent=p.cap;
    document.getElementById("dp-c").style.color=typeColor[p.type];
    document.getElementById("dp-t").innerHTML=`${p.type} · <span style="color:${p.color}">${p.status}</span>`;
    document.getElementById("dp-l").textContent=p.loc;
    panel.classList.add("open");
  } else { panel.classList.remove("open"); }
}

function closePanel(){
  activeId=null;
  document.querySelectorAll(".pi,.mk").forEach(e=>e.classList.remove("sel"));
  document.getElementById("panel").classList.remove("open");
}

function tip(evt,id){
  const p=P[id];
  document.getElementById("tn").textContent=p.name;
  const tc=document.getElementById("tc"); tc.textContent=p.cap; tc.style.color=typeColor[p.type];
  document.getElementById("tl").textContent=p.loc;
  document.getElementById("te").textContent=p.type+" Energy";
  document.getElementById("tnote").textContent=p.note;
  const ts=document.getElementById("tt-status"); ts.textContent=p.status; ts.className="tip-tag "+statusCls[p.status];
  const tt=document.getElementById("tt-type"); tt.textContent=p.type; tt.className="tip-tag "+typeCls[p.type];
  const t=document.getElementById("tip"); t.style.display="block"; posTip(evt);
}
function untip(){document.getElementById("tip").style.display="none";}
function posTip(evt){
  const t=document.getElementById("tip"),w=document.getElementById("map-wrap");
  const r=w.getBoundingClientRect();
  let x=evt.clientX-r.left+18, y=evt.clientY-r.top-14;
  if(x+275>r.width) x=x-275-36;
  if(y<0) y=4;
  t.style.left=x+"px"; t.style.top=y+"px";
}
document.getElementById("map-wrap").addEventListener("mousemove",e=>{
  if(document.getElementById("tip").style.display==="block") posTip(e);
});

buildList();
</script>
</body>
</html>